mapper.insert:
INSERT INTO enrollments (
        user_id
      , course_id
      , status
) VALUES (
        #{userId}
      , #{courseId}
      , #{status}
)
ON DUPLICATE KEY UPDATE
      status = #{status}
    , confirmed_at = NULL
    , cancelled_at = NULL

mapper.update:
UPDATE enrollments
   SET status = #{status}
     , confirmed_at = #{confirmedAt}
     , cancelled_at = #{cancelledAt}
 WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
  FROM enrollments
 WHERE user_id = #{userId}
